using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // ───────────────────────────────────────────────
    //  CalculateTotal – DataRow (inline primitive data)
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.15, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – DynamicData with ValueTuples
    // ───────────────────────────────────────────────

    [TestMethod]
    [DynamicData(nameof(InvalidTotalInputs))]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParamName)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, string expectedParam)> InvalidTotalInputs =>
    [
        (-1m,  1,   0.1m,  "unitPrice"),
        (10m, -1,   0.1m,  "quantity"),
        (10m,  1,  -0.1m,  "taxRate"),
        (10m,  1,   1.5m,  "taxRate"),
    ];

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DataRow
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% discount")]
    [DataRow(50.00, 0.0, 50.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% discount (free)")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price, 50% discount")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData with ValueTuples
    // ───────────────────────────────────────────────

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountInputs))]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    public static IEnumerable<(decimal price, decimal discountPercent)> InvalidDiscountInputs =>
    [
        (100m, -1m),
        (100m, 101m),
        (100m, 200m),
    ];

    // ───────────────────────────────────────────────
    //  FormatPrice – DataRow
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(19.99, "$", "$19.99")]
    [DataRow(1000.5, "€", "€1000.50")]
    [DataRow(0.0, "$", "$0.00")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

